import React from "react";
import { Link } from "react-router-dom";
import "./Notices.css"; // Create this file for your custom styles

export default function Notices() {
  // Example notices list (you can fetch from API later if needed)
  const notices = [
    {
      title: "Exam Form Submission",
      date: "July 15, 2025",
      description: "Last date for exam form submission without late fee."
    },
    {
      title: "Holiday Notice",
      date: "July 20, 2025",
      description: "University will remain closed on July 20th due to maintenance."
    },
    {
      title: "Placement Drive",
      date: "July 25, 2025",
      description: "Campus placement drive for final year students."
    }
  ];

  return (
    <div className="notices-container">
      <h1>📢 Notices</h1>

      <div className="notices-list">
        {notices.map((notice, index) => (
          <div key={index} className="notice-card">
            <h3>{notice.title}</h3>
            <p><strong>Date:</strong> {notice.date}</p>
            <p>{notice.description}</p>
          </div>
        ))}
      </div>

      <Link to="/dashboard" className="back-link">← Back to Dashboard</Link>
    </div>
  );
}
